```class Solution {
public:
    vector<int> evenOddBit(int n) {
        vector<int> result(2, 0);
        int index = 0;
        while (n > 0) {
            if (n & 1) {
                if (index % 2 == 0) {
                    result[0]++;
                } else {
                    result[1]++;
                }
            }
            n >>= 1;
            index++;
        }
        return result;
    }
};
